7401	\label{subsec:tensorobj_vestigial_helpers}
7402	
7403	The following are the off-critical-path Lean helper declarations supporting the
7404	flat-whiskering localizer stability \cref{lem:flat_whisker_localizer}, the
7405	flatness-free whiskering \cref{lem:whisker_of_W}, the \(R_x\)-linear stalk map
7406	\cref{lem:stalk_linear_map}, the stalkwise localizer characterisation
7407	\cref{lem:W_implies_stalkwise_iso} and the shared slice-site equivalence
7408	\cref{lem:open_immersion_slice_sheaf_equiv}. Each is proved directly in Lean.
7409	
7410	\begin{lemma}[Sectionwise left-whiskering on a simple tensor]
7411	  \label{lem:to_presheaf_whisker_left_app_tmul}
7412	  \lean{PresheafOfModules.toPresheaf_whiskerLeft_app_tmul}
7413	  \uses{lem:flat_whisker_localizer, def:scheme_modules_tensorobj}
7414	  The underlying additive map of \((F \triangleleft g)_X\) sends \(a \otimes b\) to
7415	  \(a \otimes g_X(b)\).
7416	\end{lemma}
